class ImageProcessor {
    private $uploadDir = 'uploads/';
    private $outputDir = 'processed/';
    private $allowedFormats = ['jpg', 'jpeg', 'png', 'webp', 'gif', 'bmp'];
    private $allowedOutputFormats = ['jpg', 'png', 'webp'];
    private $maxFileSize = 10485760; // 10MB
    private $maxDimension = 5000;
    
    public function __construct() {
        if (!is_dir($this->uploadDir)) {
            mkdir($this->uploadDir, 0755, true);
        }
        if (!is_dir($this->outputDir)) {
            mkdir($this->outputDir, 0755, true);
        }
    }
    
    public function processUpload($file, $outputFormat, $width = null, $height = null, $quality = 85, $maintainAspect = true) {
        // Validate file upload
        if (!isset($file['tmp_name']) || !is_uploaded_file($file['tmp_name'])) {
            return ['success' => false, 'error' => 'Invalid file upload'];
        }
        
        // Check file size
        if ($file['size'] > $this->maxFileSize) {
            return ['success' => false, 'error' => 'File size exceeds maximum allowed'];
        }
        
        // Validate file extension
        $fileExt = strtolower(pathinfo($file['name'], PATHINFO_EXTENSION));
        if (!in_array($fileExt, $this->allowedFormats)) {
            return ['success' => false, 'error' => 'Invalid file format'];
        }
        
        // Validate output format
        $outputFormat = strtolower($outputFormat);
        if (!in_array($outputFormat, $this->allowedOutputFormats)) {
            return ['success' => false, 'error' => 'Invalid output format'];
        }
        
        // Generate unique filename
        $inputFilename = uniqid('img_', true) . '.' . $fileExt;
        $inputPath = $this->uploadDir . $inputFilename;
        
        // Move uploaded file
        if (!move_uploaded_file($file['tmp_name'], $inputPath)) {
            return ['success' => false, 'error' => 'Failed to save uploaded file'];
        }
        
        // Validate dimensions
        if ($width !== null) {
            $width = (int)$width;
            if ($width <= 0 || $width > $this->maxDimension) {
                unlink($inputPath);
                return ['success' => false, 'error' => 'Invalid width dimension'];
            }
        }
        
        if ($height !== null) {
            $height = (int)$height;
            if ($height <= 0 || $height > $this->maxDimension) {
                unlink($inputPath);
                return ['success' => false, 'error' => 'Invalid height dimension'];
            }
        }
        
        // Validate quality
        $quality = (int)$quality;
        if ($quality < 1 || $quality > 100) {
            $quality = 85;
        }
        
        // Generate output filename
        $outputFilename = uniqid('processed_', true) . '.' . $outputFormat;
        $outputPath = $this->outputDir . $outputFilename;
        
        // Build ImageMagick command
        $result = $this->convertImage($inputPath, $outputPath, $outputFormat, $width, $height, $quality, $maintainAspect);
        
        // Clean up input file
        unlink($inputPath);
        
        if ($result['success']) {
            return [
                'success' => true,
                'filename' => $outputFilename,
                'path' => $outputPath,
                'url' => $this->outputDir . $outputFilename
            ];
        } else {
            return $result;
        }
    }
    
    private function convertImage($inputPath, $outputPath, $format, $width, $height, $quality, $maintainAspect) {
        $command = 'convert ' . escapeshellarg($inputPath);
        
        // Add resize parameters
        if ($width !== null || $height !== null) {
            $resizeParam = '';
            
            if ($width !== null && $height !== null) {
                if ($maintainAspect) {
                    $resizeParam = $width . 'x' . $height;
                } else {
                    $resizeParam = $width . 'x' . $height . '!';
                }
            } elseif ($width !== null) {
                $resizeParam = $width . 'x';
            } else {
                $resizeParam = 'x' . $height;
            }
            
            $command .= ' -resize ' . escapeshellarg($resizeParam);
        }
        
        // Add quality parameter
        $command .= ' -quality ' . escapeshellarg($quality);
        
        // Add output path
        $command .= ' ' . escapeshellarg($outputPath);
        
        // Execute command
        $output = [];
        $returnVar = 0;
        exec($command . ' 2>&1', $output, $returnVar);
        
        if ($returnVar !== 0) {
            return [
                'success' => false,
                'error' => 'ImageMagick conversion failed: ' . implode("\n", $output)
            ];
        }
        
        if (!file_exists($outputPath)) {
            return [
                'success' => false,
                'error' => 'Output file was not created'
            ];
        }
        
        return ['success' => true];
    }
    
    public function batchProcess($files, $outputFormat, $width = null, $height = null, $quality = 85, $maintainAspect = true) {
        $results = [];
        
        foreach ($files as $key => $file) {
            if (is_array($file['tmp_name'])) {
                // Multiple files uploaded with same field name
                for ($i = 0; $i < count($file['tmp_name']); $i++) {
                    $singleFile = [
                        'name' => $file['name'][$i],
                        'type' => $file['type'][$i],
                        'tmp_name' => $file['tmp_name'][$i],
                        'error' => $file['error'][$i],
                        'size' => $file['size'][$i]
                    ];
                    $results[] = $this->processUpload($singleFile, $outputFormat, $width, $height, $quality, $maintainAspect);
                }
            } else {
                $results[] = $this->processUpload($file, $outputFormat, $width, $height, $quality, $maintainAspect);
            }
        }
        
        return $results;
    }
    
    public function applyFilters($inputPath, $outputPath, $filters = []) {
        if (!file_exists($inputPath)) {
            return ['success' => false, 'error' => 'Input file not found'];
        }
        
        $command = 'convert ' . escapeshellarg($inputPath);
        
        foreach ($filters as $filter => $value) {
            switch ($filter) {
                case 'blur':
                    $command .= ' -blur ' . escapeshellarg($value);
                    break;
                case 'sharpen':
                    $command .= ' -sharpen ' . escapeshellarg($value);
                    break;
                case 'brightness':
                    $command .= ' -modulate ' . escapeshellarg($value . ',100,100');
                    break;
                case 'contrast':
                    $command .= ' -contrast';
                    break;
                case 'grayscale':
                    $command .= ' -colorspace Gray';
                    break;
                case 'sepia':
                    $command .= ' -sepia-tone ' . escapeshellarg($value . '%');
                    break;
                case 'rotate':
                    $command .= ' -rotate ' . escapeshellarg($value);
                    break;
                case 'flip':
                    $command .= ' -flip';
                    break;
                case 'flop':
                    $command .= ' -flop';
                    break;
            }
        }
        
        $command .= ' ' . escapeshellarg($outputPath);
        
        $output = [];
        $returnVar = 0;
        exec($command . ' 2>&1', $output, $returnVar);
        
        if ($returnVar !== 0) {
            return [
                'success' => false,
                'error' => 'Filter application failed: ' . implode("\n", $output)
            ];
        }
        
        return ['success' => true, 'path' => $outputPath];
    }
    
    public function createThumbnail($inputPath, $outputPath, $size = 150) {
        if (!file_exists($inputPath)) {
            return ['success' => false, 'error' => 'Input file not found'];
        }
        
        $size = (int)$size;
        if ($size <= 0 || $size > 500) {
            $size = 150;
        }
        
        $command = 'convert ' . escapeshellarg($inputPath) . 
                   ' -thumbnail ' . escapeshellarg($size . 'x' . $size) . 
                   ' ' . escapeshellarg($outputPath);
        
        $output = [];
        $returnVar = 0;
        exec($command . ' 2>&1', $output, $returnVar);
        
        if ($returnVar !== 0) {
            return [
                'success' => false,
                'error' => 'Thumbnail creation failed: ' . implode("\n", $output)
            ];
        }
        
        return ['success' => true, 'path' => $outputPath];
    }
    
    public function getImageInfo($imagePath) {
        if (!file_exists($imagePath)) {
            return ['success' => false, 'error' => 'Image file not found'];
        }
        
        $command = 'identify -format "%wx%h|%b|%m" ' . escapeshellarg($imagePath);
        
        $output = [];
        $returnVar = 0;
        exec($command . ' 2>&1', $output, $returnVar);
        
        if ($returnVar !== 0 || empty($output)) {
            return ['success' => false, 'error' => 'Failed to get image info'];
        }
        
        $info = explode('|', $output[0]);
        
        if (count($info) < 3) {
            return ['success' => false, 'error' => 'Invalid image info format'];
        }
        
        list($dimensions, $filesize, $format) = $info;
        list($width, $height) = explode('x', $dimensions);
        
        return [
            'success' => true,
            'width' => (int)$width,
            'height' => (int)$height,
            'filesize' => $filesize,
            'format' => $format
        ];
    }
